using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public static class ModelTrainingService
{
    public static string TrainAndEvaluate(ILoggerFactory loggerFactory)
    {
        var logger = loggerFactory.CreateLogger("ModelTraining");

        var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        var modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");

        var mlContext = new MLContext(seed: 42);

        var data = mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        logger.LogInformation("=== Model Evaluation Metrics ===");
        logger.LogInformation("MacroAccuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        logger.LogInformation("MicroAccuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        logger.LogInformation("LogLoss:          {LogLoss:F4}", metrics.LogLoss);
        logger.LogInformation("LogLossReduction: {LogLossReduction:F4}", metrics.LogLossReduction);

        mlContext.Model.Save(model, split.TrainSet.Schema, modelPath);
        logger.LogInformation("Model saved to {ModelPath}", modelPath);

        return modelPath;
    }
}

